import{_ as e,c as l,o as i,ag as t}from"./chunks/framework.dvv-DFtf.js";const m=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),r={name:"guide/getting-started.md"};function o(h,a,u,n,d,s){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>本指南将帮助您快速安装和开始使用二维码生成器 Chrome 扩展。</p><h2 id="安装扩展" tabindex="-1">安装扩展 <a class="header-anchor" href="#安装扩展" aria-label="Permalink to &quot;安装扩展&quot;">​</a></h2><h3 id="方式一-从-chrome-网上应用店安装-推荐" tabindex="-1">方式一：从 Chrome 网上应用店安装（推荐） <a class="header-anchor" href="#方式一-从-chrome-网上应用店安装-推荐" aria-label="Permalink to &quot;方式一：从 Chrome 网上应用店安装（推荐）&quot;">​</a></h3><ol><li>访问 <a href="https://chrome.google.com/webstore" target="_blank" rel="noreferrer">Chrome 网上应用店</a></li><li>搜索&quot;二维码生成器&quot;或&quot;QR Code Generator&quot;</li><li>点击&quot;添加至 Chrome&quot;按钮</li><li>在确认对话框中点击&quot;添加扩展程序&quot;</li><li>安装完成后，扩展图标将出现在浏览器工具栏中</li></ol><h3 id="方式二-开发者模式安装" tabindex="-1">方式二：开发者模式安装 <a class="header-anchor" href="#方式二-开发者模式安装" aria-label="Permalink to &quot;方式二：开发者模式安装&quot;">​</a></h3><p>如果您需要安装开发版本：</p><ol><li>下载或克隆项目代码</li><li>打开 Chrome 浏览器，访问 <code>chrome://extensions/</code></li><li>开启右上角的&quot;开发者模式&quot;</li><li>点击&quot;加载已解压的扩展程序&quot;</li><li>选择项目根目录</li><li>扩展安装完成</li></ol><h2 id="首次使用" tabindex="-1">首次使用 <a class="header-anchor" href="#首次使用" aria-label="Permalink to &quot;首次使用&quot;">​</a></h2><p>安装完成后，您可以通过以下方式开始使用：</p><h3 id="方法一-通过扩展图标" tabindex="-1">方法一：通过扩展图标 <a class="header-anchor" href="#方法一-通过扩展图标" aria-label="Permalink to &quot;方法一：通过扩展图标&quot;">​</a></h3><ol><li>访问任意网页</li><li>点击浏览器工具栏中的扩展图标</li><li>自动生成当前页面的二维码</li></ol><h3 id="方法二-通过右键菜单" tabindex="-1">方法二：通过右键菜单 <a class="header-anchor" href="#方法二-通过右键菜单" aria-label="Permalink to &quot;方法二：通过右键菜单&quot;">​</a></h3><ol><li>在网页中选中文本或右键点击链接</li><li>在右键菜单中选择&quot;生成二维码&quot;</li><li>自动生成对应内容的二维码</li></ol><h2 id="验证安装" tabindex="-1">验证安装 <a class="header-anchor" href="#验证安装" aria-label="Permalink to &quot;验证安装&quot;">​</a></h2><p>安装成功后，您应该能够：</p><ul><li>✅ 在浏览器工具栏看到扩展图标</li><li>✅ 右键菜单中出现&quot;生成二维码&quot;选项</li><li>✅ 点击扩展图标能够生成二维码</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>查看 <a href="/guide/features.html">功能特性</a> 了解所有可用功能</li><li>阅读 <a href="/guide/usage.html">使用指南</a> 学习更多使用技巧</li><li>遇到问题？查看 <a href="/guide/faq.html">常见问题</a></li></ul><h2 id="浏览器兼容性" tabindex="-1">浏览器兼容性 <a class="header-anchor" href="#浏览器兼容性" aria-label="Permalink to &quot;浏览器兼容性&quot;">​</a></h2><ul><li>✅ Chrome 88+</li><li>✅ Edge 88+</li><li>✅ 其他基于 Chromium 的浏览器 88+</li></ul><h2 id="获取帮助" tabindex="-1">获取帮助 <a class="header-anchor" href="#获取帮助" aria-label="Permalink to &quot;获取帮助&quot;">​</a></h2><p>如果您在安装或使用过程中遇到任何问题：</p><ul><li>查看 <a href="/guide/faq.html">常见问题</a></li><li>提交 <a href="https://gitee.com/mdsfe/qrcode-extension/issues" target="_blank" rel="noreferrer">Issue</a></li><li>查看 <a href="/guide/technical.html">技术文档</a></li></ul>',24)])])}const q=e(r,[["render",o]]);export{m as __pageData,q as default};
